// Extraer code y user_id del body (Vercel ya validó el JWT e inyectó user_id)
const body = $input.item.json.body || {};
const code = body.code || '';
const userId = body.user_id || '';

if (!code || !userId) {
  return [{ json: { _error: true, message: 'Faltan code o user_id en el body.' } }];
}

return [{ json: { _error: false, code, user_id: userId } }];

// Leer el access_token devuelto por Meta
const resp = $input.item.json;
const accessToken = resp.access_token || '';
const userId = $('Extraer code + user_id').item.json.user_id;

if (!accessToken) {
  return [{ json: { _error: true, message: 'Meta no devolvió access_token.', meta_response: resp } }];
}

// Descubrir WABAs del usuario
const GRAPH = 'https://graph.facebook.com/v25.0';
let wabas = [];

try {
  const wabaRes = await this.helpers.request({
    method: 'GET',
    url: GRAPH + '/me/whatsapp_business_accounts',
    qs: { fields: 'id,name', access_token: accessToken },
    json: true
  });
  if (wabaRes && Array.isArray(wabaRes.data)) wabas = wabaRes.data;
} catch (e) {
  // fallback: buscar vía businesses
  try {
    const bizRes = await this.helpers.request({
      method: 'GET',
      url: GRAPH + '/me/businesses',
      qs: { access_token: accessToken },
      json: true
    });
    for (const biz of (bizRes.data || [])) {
      try {
        const owned = await this.helpers.request({
          method: 'GET',
          url: GRAPH + '/' + biz.id + '/owned_whatsapp_business_accounts',
          qs: { fields: 'id,name', access_token: accessToken },
          json: true
        });
        if (owned && Array.isArray(owned.data)) wabas.push(...owned.data);
      } catch (innerErr) { /* skip */ }
    }
  } catch (bizErr) { /* skip */ }
}

if (wabas.length === 0) {
  return [{ json: { _error: true, message: 'No se encontraron cuentas WhatsApp Business asociadas.' } }];
}

// Descubrir phone numbers del primer WABA
const waba = wabas[0];
let phones = [];
try {
  const pnRes = await this.helpers.request({
    method: 'GET',
    url: GRAPH + '/' + waba.id + '/phone_numbers',
    qs: { fields: 'id,display_phone_number,verified_name,quality_rating', access_token: accessToken },
    json: true
  });
  if (pnRes && Array.isArray(pnRes.data)) phones = pnRes.data;
} catch (e) { /* skip */ }

if (phones.length === 0) {
  return [{ json: { _error: true, message: 'WABA encontrada pero sin números telefónicos.' } }];
}

const phone = phones[0];
return [{ json: {
  _error: false,
  user_id: userId,
  access_token: accessToken,
  waba_id: waba.id,
  waba_name: waba.name || '',
  phone_number_id: phone.id,
  display_phone_number: phone.display_phone_number || '',
  verified_name: phone.verified_name || ''
} }];

